const PERSONAL_DOMAINS = new Set(['gmail.com','googlemail.com','yahoo.com','hotmail.com','outlook.com','icloud.com','aol.com','proton.me','protonmail.com','live.com','msn.com','mail.com','yandex.com']);
const BLOCKED_PREFIXES = new Set(['abuse','admin','billing','career','careers','compliance','donotreply','finance','hr','invoice','invoices','jobs','legal','no-reply','noreply','postmaster','privacy','security','support','webmaster']);
const SAFE_PREFIXES = new Set(['bd','business','contact','growth','hello','hi','info','inquiries','inquiry','mail','marketing','opportunities','opportunity','partners','partnership','partnerships','sales','team']);
const RELEVANT_RE = /\b(?:advertis(?:e|ing)|ai|automation|b2b|brand|business(?:\s+development)?|cloud|consult(?:ant|ing|ancy)?|crm|cyber(?:security)?|data|demand\s+gen(?:eration)?|digital\s+marketing|growth|gtm|information\s+technology|it\s+service|lead\s+gen(?:eration)?|marketing|performance\s+marketing|public\s+relations|revenue|revops|saas|sales|software|technology|web(?:site)?\s+design)\b/i;
const IRRELEVANT_RE = /\b(?:adoption|artist|auto|automotive|booking|bus|car\s+rental|charter|child\s+care|collection|dating|employment|estate|event|government|helicopter|home\s+health|insurance|modeling|news|nursing|real\s+estate|recruit(?:er|ing|ment)?|rental|staffing|tour|travel|wedding)\s+agency\b/i;
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function text(value) {
  return typeof value === 'string' ? value.trim() : '';
}

function asArray(value) {
  if (Array.isArray(value)) return value.flatMap(asArray).map((item) => text(item)).filter(Boolean);
  const raw = text(value);
  if (!raw) return [];
  return raw.split(/[,\n;]/).map((item) => item.trim()).filter(Boolean);
}

function cleanUrl(value) {
  const raw = text(value);
  if (!raw || /^\[.*\]$/.test(raw)) return '';
  if (!/^https?:\/\//i.test(raw)) return '';
  return raw;
}

function domainFromUrl(value) {
  try {
    return new URL(value).hostname.toLowerCase().replace(/^www\./, '');
  } catch {
    return text(value).toLowerCase().replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0].split('?')[0];
  }
}

function domainsAlign(emailDomain, websiteDomain) {
  return emailDomain === websiteDomain || emailDomain.endsWith(`.${websiteDomain}`) || websiteDomain.endsWith(`.${emailDomain}`);
}

function collectEmails(item) {
  const fields = ['email','emails','emailAddress','email_addresses','contactEmails'];
  const values = fields.flatMap((field) => asArray(item[field]));
  return [...new Set(values.map((email) => email.toLowerCase()).filter(Boolean))];
}

function categoryText(item) {
  return [text(item.categoryName), text(item.category), ...asArray(item.categories), ...asArray(item.additionalCategories)].filter(Boolean).join(', ');
}

function csvEscape(value) {
  const raw = String(value ?? '');
  if (/[",\n]/.test(raw)) return `"${raw.replace(/"/g, '""')}"`;
  return raw;
}

const rawItems = $input.all().flatMap((entry) => {
  if (Array.isArray(entry.json)) return entry.json;
  if (Array.isArray(entry.json?.items)) return entry.json.items;
  return [entry.json];
});

const rows = [];
const rejected = [];
const seenEmails = new Set();
const seenDomains = new Set();

for (const item of rawItems) {
  const company = text(item.title) || text(item.name) || text(item.companyName) || text(item.placeName);
  const website = cleanUrl(item.website) || cleanUrl(item.websiteUrl) || cleanUrl(item.url);
  const sourceUrl = cleanUrl(item.url) || cleanUrl(item.placeUrl) || cleanUrl(item.googleMapsUri) || website;
  const websiteDomain = website ? domainFromUrl(website) : '';
  const categories = categoryText(item);

  if (categories && IRRELEVANT_RE.test(categories)) {
    rejected.push({ company, reason: 'irrelevant_business_category', categories });
    continue;
  }

  if (categories && !RELEVANT_RE.test(categories)) {
    rejected.push({ company, reason: 'low_relevance_category', categories });
    continue;
  }

  for (const email of collectEmails(item)) {
    if (!EMAIL_RE.test(email)) {
      rejected.push({ company, email, reason: 'invalid_email' });
      continue;
    }

    const [prefix, emailDomain] = email.split('@');
    if (PERSONAL_DOMAINS.has(emailDomain)) {
      rejected.push({ company, email, reason: 'personal_email_domain' });
      continue;
    }
    if (BLOCKED_PREFIXES.has(prefix)) {
      rejected.push({ company, email, reason: 'blocked_mailbox_prefix' });
      continue;
    }
    if (emailDomain === 'example.com' || emailDomain.endsWith('.test')) {
      rejected.push({ company, email, reason: 'placeholder_domain' });
      continue;
    }
    if (websiteDomain && !domainsAlign(emailDomain, websiteDomain)) {
      rejected.push({ company, email, reason: 'email_domain_does_not_match_website', websiteDomain });
      continue;
    }
    if (seenEmails.has(email) || (websiteDomain && seenDomains.has(websiteDomain))) continue;

    seenEmails.add(email);
    if (websiteDomain) seenDomains.add(websiteDomain);

    const mailboxScore = SAFE_PREFIXES.has(prefix) ? 8 : 0;
    const fitScore = Math.min(98, Math.max(70, 82 + mailboxScore + (categories ? 6 : 0)));
    const reason = `${company || emailDomain} appears relevant to outbound infrastructure, lead generation, revenue operations, or AI automation based on its public Google Maps/business listing.`;

    rows.push({
      email,
      first_name: '',
      company: company || emailDomain,
      consent_source: 'public_google_maps_listing',
      reason_to_contact: reason,
      website,
      source_url: sourceUrl,
      segment: categories || 'maps_public_listing',
      status: 'review_ready',
      fit_score: fitScore,
      evidence: sourceUrl || website
    });
  }
}

const headers = ['email','first_name','company','consent_source','reason_to_contact','website','source_url','segment','status','fit_score','evidence'];
const csv = [headers.join(','), ...rows.map((row) => headers.map((header) => csvEscape(row[header])).join(','))].join('\n');

return [{
  json: {
    ok: true,
    produced_at: new Date().toISOString(),
    rows_found: rows.length,
    rejected_count: rejected.length,
    headers,
    csv,
    rows,
    rejected
  }
}];
